css:
body {
    font-family: Arial, Helvetica, sans-serif;
    font-size: 11px;
    color: #000;
}

.company-header {
    margin-bottom: 5px;
}

.company-name {
    font-size: 16px;
    font-weight: bold;
    text-transform: uppercase;
    text-align: left;
    margin-bottom: 5px;
}

.company-address {
    margin-top: 5px;
    line-height: 1.5;
}

.party-section {
    width: 100%;
    margin-top: 5px;
    margin-bottom: 5px;
}

.party-left {
    float: left;
    width: 70%;
}

.party-right {
    float: right;
    width: 25%;
    text-align: right;
}

.clearfix {
    clear: both;
}

.separator {
    border-top: 1px solid #000;
    margin: 5px 0;
}
.details-table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 0px !important;
    margin-bottom: 0px !important;
}

.details-table td {
    padding: 0px !important;
    line-height: 1.1 !important;
    vertical-align: top;
    border: none !important;
    color:#222;
}

.details-table tr {
    height: 16px !important;
}

.label {
    width: 170px;
    font-weight: bold;
    white-space: nowrap;
}

.value {
    padding-left: 0;
}

.label {
    width: 180px;
    font-weight: bold;
    white-space: nowrap;
    border: none !important;
    padding-right: 10px;
}

.section-title {
    font-weight: bold;
    text-decoration: underline;
    margin-top: 0px !important;
    margin-bottom: 2px !important;
    padding: 0px !important;
}

.adjustment-table {
    width: 100%;
    border-collapse: separate;
    border-spacing: 0;
    margin-top: 10px;
    font-size: 13px;
}

.adjustment-table th,
.adjustment-table td {
    border: 1px solid #000 !important;
    padding: 1px 3px !important;
    line-height: 1.0 !important;
}

.adjustment-table tr {
    border: 1px solid #000 !important;
}

.adjustment-table tbody tr {
    border-bottom: 1px solid #000 !important;
}

.adjustment-table th {
    text-align: center;
    font-weight: bold;
    background: #f5f5f5;
}

.adjustment-table td {
    vertical-align: middle;
}
.company-header,
.party-section,
.details-table,
.section-title {
    font-size: 13px;
}
.adjustment-table table,
.adjustment-table tr,
.adjustment-table td,
.adjustment-table th {
    border-collapse: collapse !important;
}
.print-format {
    padding: 12px !important;
    margin: 0 !important;
}

p {
    margin: 0;
}

table {
    margin-bottom: 0;
}
.details-table + .section-title {
    margin-top: 0px !important;
}

.print-format p,
.print-format div,
.print-format table {
    margin-bottom: 0px !important;
}
.adjustment-table {
    border-collapse: collapse !important;
    border-spacing: 0 !important;
}

.adjustment-table tr {
    height: 18px !important;
}

.adjustment-table td {
    margin: 0 !important;
}

.adjustment-table th {
    margin: 0 !important;
}

html:
{% set company_doc = frappe.get_doc("Company", doc.company) %}

{% set company_links = frappe.get_all(
    "Dynamic Link",
    filters={
        "link_doctype": "Company",
        "link_name": doc.company
    },
    fields=["parent"],
    limit=1
) %}

{% if company_links %}
    {% set addr = frappe.get_doc("Address", company_links[0].parent) %}
{% else %}
    {% set addr = None %}
{% endif %}
<div class="company-name">
    {{ company_doc.company_name }}
</div>

<div class="company-address">
    {% if addr %}
        {{ addr.address_line1 or "" }}
        {% if addr.address_line2 %}, {{ addr.address_line2 }}{% endif %},
        {{ addr.city or "" }},
        {{ addr.state or "" }}
        {{ addr.pincode or "" }}
    {% endif %}
</div>

<div class="party-section">

    <div class="party-left">

        <b>To,</b><br>

        {% set links = frappe.get_all(
    "Dynamic Link",
    filters={
        "link_doctype": doc.party_type,
        "link_name": doc.party
    },
    fields=["parent"],
    limit=1
) %}

{% if links %}
    {% set b_addr = frappe.get_doc("Address", links[0].parent) %}

    <b>{{ doc.party_name or doc.party }}</b><br>

    {{ b_addr.address_line1 or "" }}
    {% if b_addr.address_line2 %}
        , {{ b_addr.address_line2 }}
    {% endif %}
    <br>

    {{ b_addr.city or "" }},
    {{ b_addr.state or "" }}
    {{ b_addr.pincode or "" }}

{% endif %}

    </div>

    <div class="party-right">

        <b>Date :</b>
        <!--{{ frappe.utils.formatdate(doc.posting_date) }}-->
        {{ frappe.utils.formatdate(frappe.utils.nowdate(), "dd-mm-yyyy") }}

    </div>

</div>

<div class="clearfix"></div>

<div class="separator"></div>
<br>
<table class="details-table">

<tr>
    <td class=""><b>Bank Name :</b></td>
    <td class="">{{ doc.paid_from }}</td>
</tr>

<tr>
    <td class=""><b>Cheque No :</b></td>
    <td class="">{{ doc.reference_no }}</td>
</tr>

<tr>
    <td class=""><b>Cheque Date :</b></td>
    <td class="">{{ frappe.utils.formatdate(doc.reference_date) }}</td>
</tr>

<tr>
    <td class=""><b>Cheque Amount :</b></td>
    <td class="">{{ doc.paid_amount }}</td>
</tr>

<tr>
    <td class=""><b>Amount In Words :</b></td>
    <td class="">{{ doc.base_in_words }}</td>
</tr>

<tr>
    <td class=""><b>Reference :</b></td>
    <td class="">{{ doc.name }}&nbsp;&nbsp;&nbsp;&nbsp; Dated :{{ frappe.utils.formatdate(doc.posting_date) }} </td>

</tr>

<tr>
    <td class=""><b>Remarks :</b></td>
     <td class=""></td>
    <!--<td class="">{{ doc.remarks }}</td>-->
</tr>

</table>
<br>
<div class="section-title">
   Clearing Adjustments :
</div>
<br>
{% for ref in doc.references %}
    {% set pi = frappe.get_doc("Purchase Invoice", ref.reference_name) %}

    {{ loop.index }}.
    Against {{ ref.reference_name }}
    Dated: {{ frappe.utils.formatdate(pi.posting_date) }}

    (Doc No: {{ pi.bill_no or "" }}
    Doc Dt: {{ frappe.utils.formatdate(pi.bill_date) if pi.bill_date else "" }}
    Doc Amt: Rs. {{ pi.grand_total }})

    Adjusted Amt: Rs. {{ ref.allocated_amount }}

    <br><br>
{% endfor %}
